def transition(state, action):
    s = dict(state)
    s["meds"] = sorted(set(str(m).strip().lower() for m in s.get("meds", []) if str(m).strip()))
    s["flagged"] = list(s.get("flagged", []))

    # Known pairwise interactions: sorted (drug_a, drug_b) -> (severity, note).
    # Severity: 1 minor, 2 moderate, 3 major.
    KB = {
        ("aspirin", "warfarin"): (3, "increased bleeding risk"),
        ("ibuprofen", "warfarin"): (3, "GI bleeding risk"),
        ("lisinopril", "spironolactone"): (3, "hyperkalemia"),
        ("lisinopril", "potassium"): (2, "hyperkalemia"),
        ("clarithromycin", "simvastatin"): (3, "rhabdomyolysis"),
        ("nitroglycerin", "sildenafil"): (3, "severe hypotension"),
        ("digoxin", "furosemide"): (2, "digoxin toxicity from hypokalemia"),
        ("metformin", "prednisone"): (1, "reduced glycemic control"),
    }

    def pair_key(a, b):
        return (a, b) if a <= b else (b, a)

    def interacting_pairs(meds):
        out = []
        meds = sorted(set(meds))
        for i in range(len(meds)):
            for j in range(i + 1, len(meds)):
                key = pair_key(meds[i], meds[j])
                if key in KB:
                    sev, note = KB[key]
                    out.append((key[0], key[1], sev, note))
        return out

    def arg_med(params):
        return str(params.get("name") or params.get("med") or "").strip().lower()

    name = action.get("name")
    params = action.get("params") or {}

    if name == "add_med":
        med = arg_med(params)
        if med and med not in s["meds"]:
            s["meds"].append(med)
            s["meds"].sort()
    elif name == "remove_med":
        med = arg_med(params)
        if med in s["meds"]:
            s["meds"].remove(med)
            # a flag is only meaningful while both of its drugs are present
            s["flagged"] = [f for f in s["flagged"] if med not in f]
    elif name == "flag_interaction":
        pairs = interacting_pairs(s["meds"])
        flagged_keys = set(f.split(":", 1)[0].strip() for f in s["flagged"])

        target = None
        req = params.get("pair")
        if isinstance(req, (list, tuple)) and len(req) == 2:
            key = pair_key(str(req[0]).strip().lower(), str(req[1]).strip().lower())
            for (pa, pb, sev, note) in pairs:
                if (pa, pb) == key:
                    target = (pa, pb, sev, note)
                    break
        if target is None:
            # auto-pick the most severe interaction not yet reviewed
            candidates = [p for p in pairs if (p[0] + "+" + p[1]) not in flagged_keys]
            candidates.sort(key=lambda p: (-p[2], p[0], p[1]))
            if candidates:
                target = candidates[0]
        if target is not None:
            pa, pb, sev, note = target
            tag = pa + "+" + pb
            if tag not in flagged_keys:
                s["flagged"].append(tag + ": " + note + " (severity " + str(sev) + ")")

    # recompute derived risk fields from the current list
    pairs = interacting_pairs(s["meds"])
    s["interaction_count"] = len(pairs)
    s["risk_score"] = sum(p[2] for p in pairs)
    s["flagged"] = sorted(set(s["flagged"]))
    s["unreviewed_count"] = max(0, len(pairs) - len(s["flagged"]))
    return s

