def perceive(data):
    if isinstance(data, dict):
        raw = data.get("meds") or data.get("medications") or []
    else:
        raw = []
        for line in str(data).splitlines():
            for chunk in line.replace(";", ",").split(","):
                raw.append(chunk)
    meds = sorted(set(str(m).strip().lower() for m in raw if str(m).strip()))
    return {"meds": meds}

